-- ==============================================
-- Trick-list CSV import (second batch)
-- ==============================================

insert into positions (name) values
  ('BACK'),
  ('BELLY'),
  ('BUDDHA'),
  ('CHEST'),
  ('DOUBLE DROPKNEE'),
  ('EXPOSURE'),
  ('INWARD DROPKNEE'),
  ('KOREAN'),
  ('LEASH'),
  ('NEVERMIND'),
  ('ROCKET'),
  ('SHOULDER'),
  ('SIT'),
  ('SOFA'),
  ('SOUP'),
  ('STAND'),
  ('YISUS')
on conflict (name) do nothing;

with pos as (select id, name from positions)
insert into tricks (
  given_name, technical_name, difficulty_tier,
  date_submitted, date_performed, original_performer,
  description, tips, video_link,
  start_position_id, end_position_id, status
)
select
  t.given_name, t.technical_name, t.difficulty_tier,
  t.date_submitted::timestamptz, t.date_performed::date,
  t.original_performer, t.description, t.tips, t.video_link,
  sp.id, ep.id,
  'approved'
from (values
  ('Sofa Roll',null,'1','2022-01-01','2016-01-01','Samuel Volery','Sit in Sofa, grab the line with both hands and press the line against your butt/thighs. Then throw yourself forward or backward, initiating the roll. To stop the roll, extend your legs.','Leash to the side can help prevent bad falls; If you fall into a backlever position let go of the line in order to save your shoulders; You can practice this trick with a hangover clipped in to save energy and get familiar with the movement without fear of falling badly','https://www.youtube.com/watch?v=Ugw1gRm-T0U','SOFA','SOFA'),
  ('Belly Roll',null,'1','2022-01-01',null,null,'With both hands on the line supporting your weight you lie on your belly and roll forward (or backward) around the line.','You can try this trick clipped into the hangover first to save energy while familiarizing yourself with the movement.','https://youtu.be/ksF8g5YrXY8?t=230','BELLY','BELLY'),
  ('Chest Roll',null,'1','2022-01-01',null,null,'From lying on your chest get some momentum with your free arm and leg, hook the line with one foot and then roll around the line grabbing it with both hands. Land back in chest.','You can wrap the foot around the line to avoid falling away from the line. Alternatively, you can press it against the line from below; You can try this trick clipped into a hangover at first to familiarize yourself with the movement.','https://youtu.be/ksF8g5YrXY8?t=182','CHEST','CHEST'),
  ('Korean Roll',null,'1','2022-01-01',null,null,'Sit in Korean, grab the line with one hand in front of you and one hand behind you and let yourself fall to the side. Land back in Korean.','Start the movement while the line moves upwards; You can try this trick clipped into a hangover first; Sometimes called "Harry Potter Roll"','https://youtu.be/ksF8g5YrXY8?t=135','KOREAN','KOREAN'),
  ('Panic','Sofa 270 to Korean','1','2022-01-01',null,null,'From Sofa you start a 180 FS spin, grab the line on your side with both hands and swing the far leg over the line to land in Korean.','Keep your center of gravity above the line.','https://www.youtube.com/watch?v=12HbVhoFloM','SOFA','KOREAN'),
  ('Hammock Roll',null,'2','2022-01-01','2016-01-01','Samuel Volery','Lie on your back and grab the line behind your head with both hands. Hook one foot under the line and roll around the line landing again in Backbounce.','As soon as you rotated all the way, let go with your hands and put your arms to the side to stop the roll. Letting go of the line feels counterintuitive, but it really helps to land the trick.','https://www.youtube.com/watch?v=maY2RjAJs1g','BACK','BACK'),
  ('Panic Roll','Sofa 270 Korean Roll','2','2022-01-01',null,'Jediah Doohan','Sit in Sofa position grab the line to the side of you with hands facing behind you. On the way up in the bounce dive down where your hands are and roll around the line. Land in Korean or Chest. Essentially you perform a 270 spin combined with a roll around the line.','It helps to separately practice the spin of the leg (Panic) and the roll around the line and then work to combine both at the same time.','https://www.youtube.com/watch?v=12HbVhoFloM','SOFA','KOREAN'),
  ('Utinni Roll','Side Sofa Roll','2','2022-01-01','2021-01-01','Michele Eibeck','Start in Sofa. Both hands next to you (right or left) holding on to the line. Then do a Sofa Roll with your body leaning towards the line where your hands are. To land the trick put the hands back to normal as you would when sitting in Sofa.',null,'https://www.instagram.com/p/CNYQEb4Jt1M/','SOFA','SOFA'),
  ('Richy Roll','Sofa Roll from Korean','2','2022-01-01',null,'Richard Schupisser','From Korean swing one leg over the line and immediately after you start the leg swing initiate a roll to finish as a Sofa Roll.','Be comfortable with Sofa Rolls first.','https://youtu.be/7kZjIAVYoyY?t=161','KOREAN','SOFA'),
  ('Back Korean Roll to Sofa',null,'3','2022-01-01','2021-01-01','Sakalomo','Do a Back Korean Roll with both hands in front. During the roll, pass the front leg between you and the line to land in Sofa.',null,'https://youtu.be/7yLCyoHgUS0?t=783','KOREAN','SOFA'),
  ('Expo Buddha Roll',null,'TBD','2022-01-01','2020-01-01','Eli Ellis','Sit in Expo Buddha, grab the line both hands on the sides, roll around the line, land again in Expo Buddha.',null,'https://youtu.be/hsALSrUdryU?t=29','BUDDHA','BUDDHA'),
  ('Flowflip','Fake 360 Korean Roll','2','2022-01-01',null,null,'From Korean, combine a 360 spin with a Korean roll around the line. Either start or land in Switch Korean. Similar to a Panic Roll but you start from Korean turned 90 further away to where you want to go.','Learn how to do a Panic Roll first. Then think of it as a Panic Roll from Korean.','https://youtu.be/12HbVhoFloM?t=199','KOREAN','CHEST'),
  ('Panic Roll to Sofa',null,'3','2022-01-01','2021-01-01','Salomé Cholet','Do a Panic Roll but before you land throw your second leg on the other side of the line as well to land back in Sofa.',null,'https://youtu.be/7yLCyoHgUS0?t=491','SOFA','SOFA'),
  ('Backbounce to Chest Roll',null,'2','2022-01-01',null,null,'From Backbounce move forward like you are going to Chest but add a Chest Roll.',null,'https://www.youtube.com/watch?v=ih6Rx-UpBfw&t=478','BACK','CHEST'),
  ('Backbounce Panic Roll',null,'3','2022-01-01',null,null,'From Backbounce swing one leg to other side and then perform a Panic Roll in the opposite direction.',null,'https://www.youtube.com/watch?v=LPsuhcOZd0Q','BACK','KOREAN'),
  ('Double Hammock Roll',null,'3','2022-01-01',null,null,'Two Hammock Rolls in one bounce.',null,'https://youtu.be/Ej2ocABoNC4?t=19688','BACK','BACK'),
  ('Back Roll Twist',null,'3','2022-01-01',null,null,'While doing the second half of a Back Roll, also turn once around the line, so do a Back Roll with a Korean Roll at the end.','For some people, this happens automatically when they try a Back Roll with bad timing. If you''re not one of those, try adding a Korean Roll in the second half of the Back Roll.','https://youtu.be/rWqH_51ztQA?t=3487','BACK','KOREAN'),
  ('Underflip','Korean 270 Spin to Back Belly Roll','2','2022-01-01','2021-01-01','Augustin Moinat','Spin with one leg 270 degrees from Korean to Belly into a Back Belly Roll.','Be comfortable with Back Belly Rolls first; Start the spin with the intention of finishing as a Back Belly Roll.','https://youtu.be/7kZjIAVYoyY?t=45','KOREAN','BELLY'),
  ('Sit to Feet',null,'2','2022-01-01',null,null,'From Sit you stand up on the top of the bounce. If you don''t have enough momentum, you can pull on the line with one arm.','Learning this is a lot about learning the correct timing which is doing the trick at the top of the bounce when you feel weightless.','https://www.youtube.com/watch?v=rdV2Jhi6U5Y','SIT','STAND'),
  ('Korean Bounce',null,'2','2022-01-01',null,null,'From standing on the line you let the line come towards your body on the top of the bounce and then slide your feet off the line to land in Korean.',null,'https://www.youtube.com/watch?v=1hPL5d3en8c','STAND','KOREAN'),
  ('Chest Bounce',null,'2','2022-01-01',null,null,'On the way to the top of the bounce you let the line come towards your body and grab it with one hand. Slide your front foot off the line and with your hand controlling the line you drop down to chest.','It can help to practice briefly grabing the line at the top of the bounce while bouncing in normal to learn to let the line come to you instead of you droping down to the line.','https://www.youtube.com/watch?v=Z11fkcCv_Qo','STAND','CHEST'),
  ('Soup to Feet',null,'2','2022-01-01',null,null,'From Soup you stand up on the top of the bounce. If you don''t have enough momentum, you can pull the line with one arm.',null,'https://www.youtube.com/watch?v=-xz9Ex3IE-M','SOUP','STAND'),
  ('Soup Bounce',null,'2','2022-01-01',null,null,'From standing on the line you let the line come towards your body on the top of the bounce and sit down keeping one foot on the line.','Feels like sitting down on something behind you; Don''t try to grab the line in case you loose the balance; It can help to practice Korean bounces first and then Soup bounces.','https://www.youtube.com/watch?v=-xz9Ex3IE-M','STAND','SOUP'),
  ('Mini-Fireflip','180 Chest Roll from Korean','2','2022-01-01','2021-01-01','Salomé Cholet','From Korean grab the line behind you and go into a Front Chest Roll. Land back in Korean looking at the other anchor.',null,'https://youtu.be/rWqH_51ztQA?t=14839','KOREAN','KOREAN'),
  ('Flow','Korean 360','2','2022-01-01',null,null,'From Korean you grab the line with both hands behind you and then swing your far leg over the line twice to do a 360 landing back in Korean.','Practice the same movement from Sofa first (= Panic).','https://www.youtube.com/watch?v=12HbVhoFloM','KOREAN','KOREAN'),
  ('Back Richy Roll','Back Sofa Roll from Korean','2',now(),null,'Richard Schupisser','From Korean let yourself fall to the side and immediately after you start the roll swing one leg over the line to finish the roll as a Back Sofa Roll.',null,'https://youtu.be/7kZjIAVYoyY?t=203','KOREAN','SOFA'),
  ('Petit Trick',null,'3',now(),'2022-01-01','Salomé Cholet','From Korean, grab the line in front of you with both hands. Shift your weight onto your arms, swing one leg over the line and start bringing it to the front. Lean backwards, release your front hand and swing the same leg as before back over the line. Finish sitting in Korean.',null,'https://youtu.be/Nk-wk2kYRso?t=109','KOREAN','KOREAN'),
  ('Backbounce Richy Roll',null,'3','2022-01-01',null,null,'From Backbounce get back up into Korean and in one fluid motion kick one leg over the line to go into a Sofa Roll.','Start the motion of getting up from Backbounce to Korean really early in the upward motion of the line.','https://www.youtube.com/watch?v=uuFlRIMmP8M&t=199','BACK','SOFA'),
  ('Sofa Roll 360',null,'4','2022-01-01',null,'Anthony Boulay','Start a Belly Roll from Sofa and add a 180 at the end.',null,'https://www.youtube.com/watch?v=ekkrE58S4O8','SOFA','SOFA'),
  ('Hammock Roll from Feet',null,'5','2022-01-01','2021-01-01','Augustin Moinat','Let the line come to your butt and grab it right behind your butt with one hand and then go to Backbounce, grab the second hand behind your head, hook with one foot and do a Hammock Roll.',null,null,'STAND','BACK'),
  ('Escoba Roll','Back Roll Twist from Feet','TBD','2022-01-01','2021-01-01','Sakalomo','Do a Back Roll from Feet but with a roll around the line as well.',null,'https://www.instagram.com/p/CMm5lqolNs4/','STAND','CHEST'),
  ('Richard Roll','Back Korean Roll BS 180','4','2022-01-01','2021-01-01','Sakalomo','Do a Back Korean Roll, pass the front leg over the line to be in Sofa, pass the back leg over the line to end in Korean facing the other anchor.',null,'https://youtu.be/7yLCyoHgUS0?t=694','KOREAN','KOREAN'),
  ('Spiral','Nevermind BS 360 to Chest','4','2022-01-01','2021-01-01','Sakalomo','Do a Nevermind up but instead of going to Feet you spin 360 backside and land in Chest.',null,'https://youtu.be/7yLCyoHgUS0?t=752','NEVERMIND','CHEST'),
  ('Double Double Drop Knee Roll',null,'TBD','2022-01-01','2021-01-01','Davis Hermes','Double Roll in Double Drop Knee.',null,'https://youtu.be/VP49hErTqM0?t=125','DOUBLE DROPKNEE','DOUBLE DROPKNEE'),
  ('Inward Drop Knee Spin to Front Sofa Roll',null,'TBD','2022-01-01','2021-01-01','Davis Hermes','Start from Inward Drop Knee, take the front foot off the line to spin 270 to go into a Front Sofa Roll.',null,'https://youtu.be/VP49hErTqM0?t=97','INWARD DROPKNEE','SOFA'),
  ('Nasty Chest','Sick Nasty to Chest','3','2022-01-01','2020-01-01','Eli Ellis','Sick Nasty landing in Chest.',null,'https://www.instagram.com/p/CJeCTdHBaUn/','SOFA','CHEST'),
  ('Nasty Chest Roll','Sick Nasty to Chest Roll','4','2022-01-01','2020-01-01','Eli Ellis','Sick Nasty to Chest Roll.',null,'https://www.instagram.com/p/CJeCTdHBaUn/','SOFA','CHEST'),
  ('Half Back Roll',null,'4','2022-01-01','2017-01-01','Guillaume Fontaine','From Backbounce do a Back Roll but stop in Shoulderstand.',null,'https://www.youtube.com/watch?v=O_E_2cB0Pcw&t=4','BACK','SHOULDER'),
  ('Dirty Bastard','FS 360 to Chest','4','2022-01-01','2021-01-01','Ian Eisenberg','From standing do a 360 spin and land in Chest.',null,'https://www.youtube.com/watch?v=A8O3iGYGPPk&t=39','STAND','CHEST'),
  ('Antihero',null,'4','2022-01-01','2020-01-01','Ian Eisenberg','Starting from Rocket, initiate a frontflip motion and let go of one hand, bring both legs over the line to land in Sofa.',null,'https://youtu.be/V0fMaONFvVY','ROCKET','SOFA'),
  ('California Roll','NH Korean Roll from Feet','TBD','2022-01-01','2020-01-01','Ian Eisenberg','From standing let the line come to your kneepit and roll to the side landing in Korean.',null,'https://youtu.be/T27UrrWAr7A','STAND','KOREAN'),
  ('Rocket Mount to Sofa',null,'4','2022-01-01','2017-01-01','Samuel Volery','From Rocket pull yourself up and then swing the legs over the line in a Sick Nasty motion. You have to let go off the line with one hand so your legs can pass to land in Sofa. Alternatively you can also thread both legs in between your arms and the line to go to Sofa.',null,'https://youtu.be/hsALSrUdryU?t=73','ROCKET','SOFA'),
  ('Triple Hammock Roll',null,'TBD','2022-01-01','2020-01-01','Tlaloc Moctezuma-Burns','Three Hammock Rolls in one bounce.',null,'https://www.youtube.com/watch?v=Se5XNo0RSP8&t=557','BACK','BACK'),
  ('Back Magic','Back Roll from Back to Back','3','2022-01-01',null,null,'Back Roll directly into Backbounce.',null,'https://www.youtube.com/watch?v=-HEZdGIakVQ','BACK','BACK'),
  ('Back Roll from Back',null,'2','2022-01-01',null,null,'Choose a shoulder that you will roll over to do this trick and put the leash on the side of this shoulder. From Backbounce wait until you are at the very top of the bounce and then pull yourself back over the shoulder and land in Korean.','Have the leash on the same side as the shoulder you roll over.','https://youtu.be/9pi0GYhBvdo?t=13','BACK','KOREAN'),
  ('Half Front Roll',null,'3','2022-01-01',null,null,'Arrange the leash such that it''s hanging down on the side of the shoulder that you are doing the shoulderstand from. Start with the shoulderstand and wait until you''re at the top of the bounce. Then push yourself to the front by pushing with your hands off of the line, roll over your back and finish the trick by landing in Korean.','If you are on the right shoulder try to thread your right arm through the leash so you don''t end up with the leash stuck on your shoulder.;Often you will slightly overrotate this trick and it can help to grab with both hands in front of you to stop the momentum.',null,'SHOULDER','KOREAN'),
  ('Makako',null,'3','2022-01-01','2021-01-01','Sakalomo','Hang in Nevermind, thread the leg that is free through your leg and the closer arm and kick through to go to a Back Belly Roll.',null,'https://youtu.be/44gWgvZrso4','NEVERMIND','BELLY'),
  ('Belly to Feet',null,'3','2022-01-01',null,null,'From Belly lift one foot up on the line, remove the hand on the same side to help you balance and then press the line down with this foot and the other hand to get the second foot up.',null,null,'BELLY','EXPOSURE'),
  ('Sofa to Feet',null,'3','2022-01-01',null,null,'From Sofa lift one foot up on the line, remove the hand on the same side to help you balance and then press the line down with this foot and the other hand to get the second foot up.','You might need to shift your weight to the opposite side of the foot you are trying to get onto the line; If you have access to a rodeoline with mats, this is a trick you can practice there first.','https://www.youtube.com/watch?v=_CqGa-iBrHE','SOFA','EXPOSURE'),
  ('Korean to Feet',null,'3','2022-01-01',null,null,'From Korean you get both feet on top of the line at the same time followed by a Sit Mount in the same bounce or you put one foot on the line followed by a Soup to Feet in the same bounce.','Depending on your preferred variation, practice Sit to Feet or Soup to Feet first and then korean to feet will be a natural upgrade when you have the former solid enough.','https://www.youtube.com/watch?v=1hPL5d3en8c','KOREAN','STAND'),
  ('Back to Feet',null,'3','2022-01-01',null,null,'From Backbounce go to Korean and add a Korean to Feet in the same bounce. Alternatively, you can hook the line with one foot to assist pulling yourself up.','Depending on your preferred variation, practice Sit to Feet or Korean to Feet first.','https://www.youtube.com/watch?v=MpfpSkwcqsg','BACK','STAND'),
  ('Chest to Feet',null,'3','2022-01-01',null,null,'From Chest you push the line down with one arm and the back foot in order to put your front foot on the line.',null,'https://www.youtube.com/watch?v=Z11fkcCv_Qo','CHEST','STAND'),
  ('Back Bounce',null,'3','2022-01-01',null,null,'From standing on the line you let the line come towards your body on the top of the bounce and when your butt is on the line, slide your feet off the line and lean all the way back to land in Back.','Learn a Korean Bounce first, practice leaning back from Korean to Back, and then combine both motions into one bounce.','https://www.youtube.com/watch?v=MpfpSkwcqsg','STAND','BACK'),
  ('Sit Bounce',null,'3','2022-01-01',null,null,'From standing on the line you let the line come towards your body on the top of the bounce and sit down keeping both of your feet on the line.','Feels like sitting down on something behind you; Don''t try to grab the line in case you loose your balance; It can help to practice Korean bounces first, then Soup bounces and then Sit bounces.','https://www.youtube.com/watch?v=rdV2Jhi6U5Y','STAND','SIT'),
  ('Sofa Bounce',null,'3','2022-01-01',null,null,'From Exposure let the line come towards your body and grab the line with both hands then slide your feet off to land in Sofa.','It can help to practice briefly grabing the line at the top of the bounce while bouncing in Expo; This way you can learn to let the line come towards your butt instead of you droping down to Sofa.','https://www.youtube.com/watch?v=_CqGa-iBrHE','EXPOSURE','SOFA'),
  ('Belly Bounce',null,'3','2022-01-01',null,null,'From Exposure let the line come towards your body and grab the line with both hands then slide your feet off to land in Belly.',null,null,'EXPOSURE','BELLY'),
  ('Reverse Panic Roll',null,'3','2022-01-01',null,null,'From Korean you do a 270 BS spin to the front and then go into a Front Sofa Roll.',null,null,'KOREAN','SOFA'),
  ('Wolf Flip','Reverse Flowflip','4','2022-01-01',null,null,'From Korean initiate a 360 BS spin to the front and simultaneously start a roll backwards, spin for a full 360 to land back in Korean after the roll is finished.',null,null,'KOREAN','KOREAN'),
  ('Sofa 360',null,'3','2022-01-01',null,null,'From Sofa do a 360 spin by doing a 180 to Belly and another 180 from Belly to Sofa.','You can start by practicing the 180 from Belly to Sofa; You need to find your balance over the line and to land it you need to stick your butt out.',null,'SOFA','SOFA'),
  ('Wolf','Reverse Flow','3',now(),null,null,'From Korean, grab the line in front of you and pass one leg over the line twice (first behind you, at the end in front of you) to do a 360 spin. It is the inverse motion of a Flow.',null,'https://youtu.be/d5GTyM0ReFE?t=45','KOREAN','KOREAN'),
  ('Reverse Panic',null,'3',now(),null,null,'From Korean, grab the line in front of you and pass one leg over the line to do a 270 spin landing in Sofa. It is the inverse motion of a Panic.',null,null,'KOREAN','SOFA'),
  ('Nevermind',null,'4','2022-01-01','2015-01-01','Friedi Kuehne','From the catch position (Nevermind), pull yourself up, put the hooking foot on top of the line, and push yourself up to put the second foot back on the line.',null,'https://www.youtube.com/watch?v=JXLw6K-AX7I','NEVERMIND','STAND'),
  ('Flare','Sick Nasty','4','2022-01-01','2018-01-01','Samuel Volery','From Sofa you grab the line next to you with both hands and swing the legs over the line and around behind you and again over the line on the other side of your hands back to Sofa.',null,'https://www.youtube.com/watch?v=_xAtTSwu7M8','SOFA','SOFA'),
  ('Shoulder Roll',null,'4','2022-01-01',null,'Anthony Boulay','From Shoulderstand, tuck your legs, roll to one side and extend your legs for the landing back in Shoulderstand.',null,'https://youtu.be/hsALSrUdryU?t=81','SHOULDER','SHOULDER'),
  ('Butter','FS 360 Butt Flatspin','4','2022-01-01','2021-01-01','Tlaloc Moctezuma-Burns','In Butt grab the line with the front hand behind you. Then pull with that arm to do a 360 landing back in Sofa.',null,'https://youtu.be/RDVaUFdqMmE?t=237','SOFA','SOFA'),
  ('Rocket Mount to Back Sofa Roll',null,'5','2022-01-01','2020-01-01','Sakalomo','From Hanging swing your legs beside your hands (similar to a Sick Nasty movement) and go into a Back Sofa Roll.',null,'https://youtu.be/n_YEN0Yva5I?t=70','ROCKET','SOFA'),
  ('Belly Roll to Feet',null,'5','2022-01-01','2018-01-01','Enzo Fuchs','From Belly turn one time around the line and land in Exposure in one bounce.',null,'https://www.youtube.com/watch?v=qUxUNfgvoPs&t=107','BELLY','EXPOSURE'),
  ('Chest Roll to Front Roll',null,'5','2022-01-01','2017-01-01','Guillaume Fontaine','Start by doing a Chest Roll and then do a Front Roll by pushing with one foot off the line.',null,'https://youtu.be/O_E_2cB0Pcw?t=40','CHEST','KOREAN'),
  ('FS 360 Roll Down to Chest',null,'5','2022-01-01','2021-01-01','Ian Eisenberg','From standing do a 360 spin while doing a roll around the line and land in Chest.',null,'https://www.youtube.com/watch?v=A8O3iGYGPPk&t=86','STAND','CHEST'),
  ('Rock''n''Roll','Reverse Rocket Mount to Sofa','4','2022-01-01','2020-01-01','Ian Eisenberg','From Rocket do a Reverse Rocket Mount but instead of going to Feet you land in Sofa.',null,'https://www.youtube.com/watch?v=5rGCjINEs0Q&t=39','ROCKET','SOFA'),
  ('Shrimpflip',null,'4','2022-01-01','2021-01-01','Ian Eisenberg','From the Rocket you kick your feet through your arms between the line and your body, regrab the line and land back in Rocket.',null,'https://youtu.be/7yLCyoHgUS0?t=1501','ROCKET','ROCKET'),
  ('Cordova Roll',null,'5','2022-01-01','2020-01-01','Ian Eisenberg','Start like a Reverse Rocket Mount and go into a Double Drop Knee position but then fully extend your hips while keeping the line at your ankles behind your back. Roll around the line and end up back in Rocket.',null,'https://youtu.be/Ab2gW1rv5e8?t=58','ROCKET','ROCKET'),
  ('Full Rocket','Rocket 360 to Rocket','5','2022-01-01','2021-01-01','Ian Eisenberg','From Rocket do a 360 around the horizontal axis perpendicular to the line and land again in Rocket.',null,'https://youtu.be/aYsX0kpCnAg?t=23','ROCKET','ROCKET'),
  ('Rocket Rewind','Rocket Roll 180 to Sofa','5','2022-01-01','2021-01-01','Ian Eisenberg','Start by doing a Rocket Mount but then go into a Belly Roll finishing with a 180 to Sofa.','Get a lot of momentum for the Rocket Roll and in the end do a 180 and stick your butt out as in the Sofa Roll 360.','https://youtu.be/aYsX0kpCnAg?t=6','ROCKET','SOFA'),
  ('Can of Soup','Soup Roll to Feet','4','2022-01-01','2019-01-01','Justin Wagers','From Soup, you grab one hand in front and one behind, you roll to the side of the leg on the line, put the second foot up, and pull yourself up to land to Feet in normal stance.',null,'https://youtu.be/xqblad7pNLA?t=300','SOUP','STAND'),
  ('Sick Nasty Roll',null,'4','2022-01-01','2019-01-01','Samuel Volery','Sick Nasty with an additional Back Sofa Roll in the same bounce.','Regrab with the far hand to get into the Back Sofa Roll.','https://youtu.be/uOuqykzwN7w?t=65','SOFA','SOFA'),
  ('Baguette','Sofa 360 to Feet','5','2022-01-01','2020-01-01','Tlaloc Moctezuma-Burns','From Sofa you do a 360, put the outter foot on the line first and then put the second foot on to land in Exposure.',null,'https://youtu.be/hsALSrUdryU?t=49','SOFA','EXPOSURE'),
  ('Chest Roll to Feet',null,'4','2022-01-01',null,null,'Do a Chest Roll and in the end of the roll push yourself away from the line to put your front foot on.',null,'https://www.youtube.com/watch?v=qUxUNfgvoPs&t=35','CHEST','STAND'),
  ('Fake Sick Nasty Roll',null,'4','2022-01-01',null,null,'Sick Nasty Roll but starting from Korean.',null,'https://youtu.be/hsALSrUdryU?t=153','KOREAN','SOFA'),
  ('Flare to Feet','Sick Nasty to Feet','4','2022-01-01',null,null,'From Sofa you grab the line next to you with both hands and swing the legs over the line and around behind you and then you land in Exposure on the other side of your hands.',null,'https://youtu.be/Ej2ocABoNC4?t=18159','SOFA','EXPOSURE'),
  ('Obi Wan',null,'5','2022-01-01',null,null,'Similar to Rocket Mount. Instead of putting both feet between your hands, put one foot outside of your hands, then put the second foot between the hands to land in Exposure.',null,null,'ROCKET','STAND'),
  ('Back Can of Soup',null,'4','2022-01-01','2021-01-01','Ian Eisenberg','From Soup you roll to the side in the direction of your leg that is hanging down and land to Feet in normal stance.',null,'https://youtu.be/IDYpoOE8Kq8?t=32','SOUP','STAND'),
  ('Sofa Roll to Feet',null,'4','2022-01-01',null,null,'Do a Sofa Roll and during the roll you lean a bit to the side so you can get one foot on the line, to finish the roll you get the second foot up and stand up.','An easier variation is to already start with one foot on the line when you start the roll.','https://youtu.be/rWqH_51ztQA?t=12678','SOFA','EXPOSURE'),
  ('Back Sofa Roll to Feet',null,'4','2022-01-01',null,null,'Do a Back Sofa Roll and during the roll you lean a bit to the side so you can get one foot on the line, to finish the roll you get the second foot up and stand up.','An easier variation is to already start with one foot on the line when you start the roll.',null,'SOFA','EXPOSURE'),
  ('Rocket Nasty',null,'5','2022-01-01','2021-01-01','Ian Eisenberg','It''s like a Sick Nasty from Rocket to Rocket, but passing the legs over the line to the front.',null,null,'ROCKET','ROCKET'),
  ('Rocket Mount to DDK',null,'5','2022-01-01',null,'Enzo Fuchs','Rocket Mount landing in Double Drop Knee.',null,null,'ROCKET','DOUBLE DROPKNEE'),
  ('Fake Orbital','Orbital 180','4','2022-01-01',null,null,'Orbital 180 landing in Chest. The 180 makes it easier compared to the normal Orbital. Also called Norbital.',null,null,'STAND','CHEST'),
  ('Fireflip to Shoulder',null,'5','2022-01-01','2022-01-01','Samuel Volery','From Korean grab the line behind you and go into a Front Chest Roll. Land on your shoulder to finish the trick.',null,'https://www.instagram.com/p/CYPMq9BJg55/','KOREAN','SHOULDER'),
  ('Sushi','Korean Pop','4','2022-01-01','2021-01-01','Ian Eisenberg','Korean from Feet and Korean to Feet in one bounce. You have to let the line pop at the beginning.','Consider buying a cup to protect your genitals (applies to men and women).','https://youtu.be/7yLCyoHgUS0?t=1322','STAND','STAND'),
  ('Nevermind 180',null,'5','2022-01-01','2021-01-01','Sebastian Egger','Start as you would for a Nevermind but then use your foot that is in contact with the line to initiate a FS spin and do a 180 before you land in Exposure.',null,'https://youtu.be/Ej2ocABoNC4?t=22796','NEVERMIND','EXPOSURE'),
  ('Richy Roll to Feet',null,'5','2022-01-01',null,null,'Front Sofa Roll to Feet but starting from Korean so you have to swing one leg over the line first.',null,null,'KOREAN','EXPOSURE'),
  ('Back Richy Roll to Feet',null,'5','2022-01-01',null,null,'Back Sofa Roll to Feet but starting from Korean so you have to swing one leg over the line first.',null,null,'KOREAN','EXPOSURE'),
  ('360 Spin',null,'5','2022-01-01',null,null,'Do a 360 spin, restepping with your feet twice.',null,null,'STAND','STAND'),
  ('Butter Roll',null,'5','2022-01-01',null,null,'From Butt grab the line with one hand behind your back. With this hand you pull yourself to do a 360 Butt Flatspin and add a Back Sofa Roll in the end.',null,null,'SOFA','SOFA'),
  ('Pastisroll','One hand one foot Can of Soup','5',now(),'2021-01-01','Oscar Defoor','Can of soup with only using the back hand and the front foot hooking the line.',null,null,'SOUP','STAND'),
  ('Double Drop Knee Roll',null,'4',now(),null,null,'From Double Drop Knee grab the line with both hands and roll to the front landing back in Double Drop Knee.',null,null,'DOUBLE DROPKNEE','DOUBLE DROPKNEE'),
  ('Kamikaze','Feet to Shoulder','4','2022-01-01',null,'Samuel Volery','From Standing, grab the line with your hands, take off your front foot, and use the back foot to push yourself into the Shoulderstand.',null,'https://youtu.be/9Ab1JPDJR-I?t=234','STAND','SHOULDER'),
  ('Panic Roll to Feet',null,'5','2022-01-01',null,'Anthony Boulay','Do a Panic Roll and put your back foot onto the line. When you finished the rotation put the second foot up and stand up.','During the roll get your far foot on the line. At the end of the roll get your second foot up on the line.','https://www.youtube.com/watch?v=hQaJ54xvfOA','SOFA','EXPOSURE'),
  ('Rocket Mount',null,'5','2022-01-01','2017-01-01','Samuel Volery','At the bottom of the bounce, kick your legs to the back, immediately afterwards kick them to the front again. Then do a final kick to the back while pulling the line down in front of you, and put your feet on the line.','Get some momentum with your legs in the bottom part of the bounce. As soon as you are weightless pull the line below your feet.; This trick doesn''t require as much strength as you would think! It''s all about getting enough momentum with your legs.; If you can''t hold the bounce in the Rocket position try again with less bounce.','https://youtu.be/zSfwTW4vJas','ROCKET','EXPOSURE'),
  ('Reverse Rocket Mount to Double Drop Knee',null,'5','2022-01-01','2021-01-01','Domingo Capo','From Hanging do a Reverse Rocket Mount but land in Double Drop Knee.',null,'https://youtu.be/7yLCyoHgUS0?t=1775','ROCKET','DOUBLE DROPKNEE'),
  ('Double Drop Knee Roll to Feet',null,'5','2022-01-01','2021-01-01','Domingo Capo','From Double Drop Knee do a Double Drop Knee Roll and stand up to land in Exposure.',null,'https://youtu.be/7yLCyoHgUS0?t=1767','DOUBLE DROPKNEE','EXPOSURE'),
  ('Hammock Back Roll',null,'5','2022-01-01','2017-01-01','Guillaume Fontaine','Do a Hammock Roll and finish with a Back Roll in the same bounce.',null,'https://youtu.be/Ej2ocABoNC4?t=22785','BACK','KOREAN'),
  ('Half Back Roll to Shoulder Roll',null,'5','2022-01-01','2017-01-01','Guillaume Fontaine','Do a Half Back Roll but add a Shoulder Roll to finish the trick.',null,'https://www.youtube.com/watch?v=O_E_2cB0Pcw&t=61','BACK','SHOULDER'),
  ('Frontflop','Front Roll from Feet','5','2022-01-01','2017-01-01','Guillaume Fontaine','From Standing grab the line as in a Kamikaze, but then roll over your back and land in Korean.','Thread your arm through the leash so it is not wrapped around your shoulder.','https://youtu.be/n2z3IyeQSj4?t=41','STAND','KOREAN'),
  ('Chest Roll BS 360 Flatspin',null,'5','2022-01-01','2021-01-01','Ian Eisenberg','Do a Chest Roll followed by a BS 360 Chest Flatspin.',null,'https://www.youtube.com/watch?v=n2z3IyeQSj4&t=25','CHEST','CHEST'),
  ('Mini-Cube','Half Nasty 180 Front Sofa Roll','5','2022-01-01','2021-01-01','Ian Eisenberg','Do a Half Nasty 180 with an additional Front Sofa Roll. The motions happen at the same time rather than one after each other.',null,'https://www.youtube.com/watch?v=7yLCyoHgUS0&t=1142','SOFA','SOFA'),
  ('Rocket Rewind Roll','Rocket 180 Roll to Sofa Roll','6','2022-01-01','2021-01-01','Ian Eisenberg','Rocket Rewind with an additional Back Sofa Roll in the end.',null,'https://youtu.be/n2z3IyeQSj4?t=47','ROCKET','SOFA'),
  ('Backbounce Panic Roll to Feet',null,'6','2022-01-01','2018-01-01','Lukas Irmler','From Backbounce go into the Panic Roll to Feet.',null,'https://youtu.be/Se5XNo0RSP8?t=437','BACK','EXPOSURE'),
  ('Dibahia Roll (Backflop)','Back Roll from Feet','5','2022-01-01',null,'Matheus Stoco Vidal','From standing you jump straight backwards and roll over your shoulder to land in Korean.','Have the leash on the same side as the shoulder you roll over; it''s a bit easier if you don''t jump backwards, but instead roll over your back.','https://youtu.be/Ej2ocABoNC4?t=18150','STAND','KOREAN'),
  ('Rocket Mount to Shoulder',null,'6','2022-01-01','2017-01-01','Samuel Volery','From Rocket go up to shoulder stand.','When dropping down to Rocket already grab with the hands as you would for the Shoulderstand then you don''t have to regrab.','https://youtu.be/Se5XNo0RSP8?t=527','ROCKET','SHOULDER'),
  ('Rocket Backflip',null,'6','2022-01-01','2021-01-01','Sebastian Egger','In Rocket do a backflip, completely letting go of the line and landing back in Rocket.',null,'https://youtu.be/9Ab1JPDJR-I?t=168','ROCKET','ROCKET'),
  ('Sarah Roll','Side Roll over Neck','5','2022-01-01','2020-01-01','Tlaloc Moctezuma-Burns','Sit in Sofa and roll to the side over your neck back to Sofa.','There are more comfortable tricks to try.','https://youtu.be/Se5XNo0RSP8?t=563','SOFA','SOFA'),
  ('Back Chest Roll to Feet',null,'4','2022-01-01',null,null,'Do a Back Chest Roll and in the end of the roll push yourself away from the line to put your front foot on.',null,'https://www.instagram.com/p/CUITT4wgvmH/','CHEST','STAND'),
  ('Nasty Korean','Full Flare from Korean','6','2022-01-01','2021-01-01','Sebastian Egger','Full Flare (see breakdancing) from Korean to Korean.',null,null,'KOREAN','KOREAN'),
  ('Yisus Mount',null,'5','2022-01-01','2021-01-01','Leonardo Ferrari','Hanging on the line grabbing it with both hands and having it run under your elbows and shoulders press yourself up to Exposure.','Watch out for your shoulders on this one!','https://www.instagram.com/p/CXeLk4Qldu_/','YISUS','EXPOSURE'),
  ('Orbital to Sofa',null,'5','2022-01-01','2021-01-01','Ian Eisenberg','Like an Orbital but instead of throwing your leg over the line, put the line under your butt to# land in Sofa.',null,null,'STAND','SOFA'),
  ('Shaolin',null,'5','2022-01-01','2021-01-01','Ian Eisenberg','Like a Rocket Mount to Sofa but instead of landing in Sofa you pop both legs through your arms and then drop back to Rocket.',null,null,'ROCKET','ROCKET'),
  ('Reverse Panic Roll to Feet',null,'6','2022-01-01',null,null,'From Korean you do a 270 BS spin to the front and then go into a Front Sofa Roll to Feet.',null,null,'KOREAN','EXPOSURE'),
  ('Wolf Flip to Feet','Reverse Flowflip to Feet','6','2022-01-01','2022-01-01','Ian Eisenberg','Reverse Flowflip to Feet.',null,'https://www.instagram.com/p/CfrFKq2tP0m/','KOREAN','STAND'),
  ('Shrimpflip 180 to Belly',null,'5','2022-01-01',null,null,'From Rocket thread your legs in between your arms and the line and let go with one hand to start the 180. Land in Belly.',null,null,'ROCKET','BELLY'),
  ('Frontroll to Feet',null,'6','2022-01-01',null,null,'From Shoulder push yourself forward to roll over your back and land on your Feet.',null,null,'SHOULDER','STAND'),
  ('Side Roll',null,'5',now(),null,null,'From Sofa grab the line with one hand in the direction that you''re rolling towards and pull on the line to initiate a sidewards roll. Roll over your lower back until you land back in Sofa.','Grabbing the line with both hands shortly before landing can help to readjust your position a bit.','https://youtu.be/7yLCyoHgUS0?t=1400','SOFA','SOFA'),
  ('Reverse Obi-Wan',null,'6','2022-01-01',null,'Sakalomo','From Rocket swing your legs up (feet first) and put one foot on the line outside of your hands. When you finish the rotation, put the second foot on and land in Exposure.','Bring the foot that does not go to the line straight away far over the line to get your center of gravity right over the line and then put it on the line in the end of the trick.','https://youtu.be/n_YEN0Yva5I?t=161','ROCKET','STAND'),
  ('Back Roll to Feet',null,'6','2022-01-01','2017-01-01','Guillaume Fontaine','Do a Back Roll, then put your back foot on the line first, and press yourself up to put the second foot on.',null,'https://www.youtube.com/watch?v=Se5XNo0RSP8&t=662','BACK','STAND'),
  ('Orbital',null,'5','2022-01-01','2020-01-01','Ian Eisenberg','Grab the line with your back hand, bring it up around your body by passing it to your other hand, and finally pass your leg over the line to land in Korean.',null,'https://www.youtube.com/watch?v=t6xPycD-JbY','STAND','KOREAN'),
  ('Hammock Roll to Feet',null,'5','2022-01-01','2021-01-01','Augustin Moinat','Grab the line with one hand behind your head and the second hand below your back, do a Hammock Roll, and go to Feet.',null,null,'BACK','STAND'),
  ('Can of Bisque','BS 270 Can of Soup','6','2022-01-01','2021-01-01','Davis Hermes','Do a Can of Soup followed by a BS 270 spin landing in Exposure.',null,'https://youtu.be/VP49hErTqM0?t=356','SOUP','EXPOSURE'),
  ('Exporbital','Exposure Orbital to Sofa','5','2022-01-01','2021-01-01','Ian Eisenberg','Orbital to Sofa but starting in Exposure.',null,'https://www.youtube.com/watch?v=2ykEngQRgKo&t=6','EXPOSURE','SOFA'),
  ('Mini-Eisenvader','Antihero from Feet','7','2022-01-01','2021-01-01','Ian Eisenberg','From Exposure you grab the line with one hand and roll forward. As soon as you are under the line you perform an Antihero landing in Sofa.',null,'https://youtu.be/7yLCyoHgUS0?t=1437','EXPOSURE','SOFA'),
  ('180 to Orbital',null,'6','2022-01-01','2021-01-01','Ian Eisenberg','Do a 180 spin followed by an Orbital.',null,'https://youtu.be/A8O3iGYGPPk?t=146','STAND','KOREAN'),
  ('Rocket Mount 180',null,'6','2022-01-01','2020-01-01','Ian Eisenberg','Start as you would for the Rocket Mount, and then half way up you push with one hand and pull with the other to initiate a 180 spin, landing in Exposure.','The movement in the end is comparable to the Sofa 360 to Feet.','https://youtu.be/dG9sJvKjg6E?t=285','ROCKET','EXPOSURE'),
  ('Sick Nasty Double Roll',null,'5','2022-01-01','2020-01-01','Ian Eisenberg','Sick Nasty Roll with an additional Back Sofa Roll in the same bounce.',null,'https://youtu.be/qLEnzTtvTcA?t=21','SOFA','SOFA'),
  ('Sofa 360 Double Roll',null,'5','2022-01-01','2020-01-01','Justin Wagers','Do a Sofa Roll 360 with an additional Back Sofa Roll in the end.','You have to be fast with the regrab.','https://youtu.be/hsALSrUdryU?t=134','SOFA','SOFA'),
  ('Fire Flip','BS 180 Front Korean Roll to Feet','6','2022-01-01','2021-01-01','Salomé Cholet','Do a Mini-Fireflip to Feet.',null,'https://youtu.be/HecUpHXRpDw?t=302','KOREAN','STAND'),
  ('Back Belly Roll to Feet',null,'5','2022-01-01',null,null,'Do a Back Belly Roll to Feet.',null,'https://www.youtube.com/watch?v=7yLCyoHgUS0&t=723','BELLY','EXPOSURE'),
  ('Flowflip to Feet',null,'5','2022-01-01',null,null,'Do a Flowflip to Feet.','During the flip get your far foot on the line. At the end of the flip get your second foot up on the line; A lot of people do it landing in Exposure.','https://www.youtube.com/watch?v=kn15JZJOuAg','KOREAN','EXPOSURE'),
  ('Backbounce Richy Roll to Feet',null,'5','2022-01-01',null,null,'From Backbounce perform a Richy Roll but land it to Feet.',null,'https://www.youtube.com/watch?v=uuFlRIMmP8M&t=260','BACK','EXPOSURE'),
  ('Shoulder Roll to Feet',null,'5','2022-01-01',null,null,'From Shoulderstand roll to one side and get your feet on the line. Land in Exposure.',null,'https://www.youtube.com/watch?v=7CZuU59KY_c&t=71','SHOULDER','EXPOSURE'),
  ('Panic Roll to Shoulder',null,'5','2022-01-01',null,null,'Do the Panic Roll but instead of landing in Chest you go into Shoulderstand.','Regrab with one hand to land comfortably in Shoulderstand.','https://youtu.be/uOuqykzwN7w?t=48','SOFA','SHOULDER'),
  ('Yoda Roll',null,'6','2022-01-01','2016-01-01','Samuel Volery','From Exposure grab the line with both hands and roll around the line landing back in Exposure.','Try to wait a bit after hitting the bottom of the bounce before you start with the trick. If you start too early you will kill the bounce.','https://www.youtube.com/watch?v=DgVLWsChXFM','EXPOSURE','EXPOSURE'),
  ('Back Yoda Roll',null,'6','2022-01-01','2017-01-01','Samuel Volery','From Exposure grab the line with both hands and roll around the line backwards landing back in Exposure.','Try to wait a bit after hitting the bottom of the bounce before you start with the trick. If you start too early you will kill the bounce.','https://youtu.be/QJzX6gaYQoM?t=34','EXPOSURE','EXPOSURE'),
  ('Barrel Roll',null,'6','2022-01-01',null,null,'From your normal stance grab the line with both hands and roll around the line landing back in the starting position.',null,'https://www.youtube.com/watch?v=dG9sJvKjg6E&t=396','STAND','STAND'),
  ('Back Barrel Roll',null,'6','2022-01-01',null,null,'From your normal stance grab the line with both hands and roll around the line backwards landing back in the starting position.',null,'https://www.youtube.com/watch?v=dG9sJvKjg6E&t=396','STAND','STAND'),
  ('Reverse Whatever',null,'7','2022-01-01','2021-01-01','Sebastian Egger','Drop into the leash and on the way up climb the leash and finish with a Reverse Obi-Wan.','Amazing leash fall saving trick.','https://youtu.be/Ej2ocABoNC4?t=23482','LEASH','EXPOSURE'),
  ('Sick Nasty Roll from Feet',null,'6','2022-01-01','2021-01-01','Ian Eisenberg','Sick Nasty Roll but starting in Exposure.',null,'https://youtu.be/aAq4Tf8naOM?t=80','EXPOSURE','SOFA'),
  ('Flower','Korean 540 to Feet','6','2022-01-01','2021-01-01','Tim Odermatt','Like a normal Flow to Feet but adding a 180 at the end.',null,'https://youtu.be/aAq4Tf8naOM?t=131','KOREAN','STAND'),
  ('Spaghetti Roll','Double Hammock Roll from Feet','6','2022-01-01','2021-01-01','Augustin Moinat','Do a Hammock Roll from Feet and add an extra Hammock Roll at the end.',null,null,'STAND','BACK'),
  ('Tamatta Roll','Double Sofa Roll to Feet','6','2022-01-01','2021-01-01','Axel Weber','Double Sofa Roll landing in Exposure.',null,'https://youtu.be/9Ab1JPDJR-I?t=250','SOFA','EXPOSURE'),
  ('Tre Nasty','Sick Nasty 360','6','2022-01-01','2021-01-01','Ian Eisenberg','Start with the motion of a Half Nasty 180 but pass your legs over the line once more and keep spinning to do a full 360 landing back in the starting position.',null,'https://youtu.be/wHPNMiKrHsQ?t=44','SOFA','SOFA'),
  ('Chest Roll 180 Flatspin to Feet',null,'6','2022-01-01','2021-01-01','Ian Eisenberg','Do a Chest Roll followed by a 180 Chest Flatspin to Feet.',null,'https://www.youtube.com/watch?v=n2z3IyeQSj4&t=16','CHEST','EXPOSURE'),
  ('Shapeshifter',null,'6','2022-01-01','2021-01-01','Ian Eisenberg','From Exposure do a front flip off the line and catch the line to land in Rocket.',null,'https://www.youtube.com/watch?v=QrUyUx8oJUY','EXPOSURE','ROCKET'),
  ('Rocket Mount Side Roll to Sofa',null,'6','2022-01-01','2021-01-01','Ian Eisenberg','From Rocket Mount do a Side Roll with the axis of rotation perpendicular to the line and land in Sofa.','Flip one of your hands to allow for a better initiation of the momentum.','https://www.youtube.com/watch?v=7yLCyoHgUS0&t=1082','ROCKET','SOFA'),
  ('Sushi Roll','Korean Roll from Feet to Feet','6','2022-01-01','2021-01-01','Ian Eisenberg','Do a Korean Roll but starting from Feet and landing to Feet.',null,'https://youtu.be/Ab2gW1rv5e8?t=16','STAND','STAND'),
  ('Sakalorbital','180 Orbital to Feet','7','2022-01-01','2020-01-01','Ian Eisenberg','Grab the line with one hand, bring it around your body by passing it to your other hand above your head. Put the line back under your feet to land in Exposure.',null,'https://youtu.be/Ab2gW1rv5e8?t=69','STAND','EXPOSURE'),
  ('Tre Nasty to Chest','Sick Nasty 360 to Chest','6','2022-01-01','2021-01-01','Ian Eisenberg','Tre Nasty landing in Chest.',null,'https://youtu.be/eP2pBpKv4wI?t=39','SOFA','CHEST'),
  ('Freak Nasty to Feet',null,'6','2022-01-01','2020-01-01','Ian Eisenberg','Do a Freak Nasty landing in Exposure.',null,'https://youtu.be/T27UrrWAr7A?t=36','SOFA','EXPOSURE'),
  ('540 Spin',null,'6','2022-01-01','2021-01-01','Joshua Leupolz','Spin 540 on the line in a standing position.',null,'https://youtu.be/qUxUNfgvoPs?t=46','STAND','STAND'),
  ('Reverse Rocket Mount',null,'6','2022-01-01','2019-01-01','Samuel Volery','From Rocket swing your legs up (feet first) and put both feet on the line inside of your hands and land in Exposure.','Sam and Ian have quite different techniques for this trick. Try both and see which one suits you (or do your own variation of course).','https://youtu.be/uOuqykzwN7w?t=171','ROCKET','EXPOSURE'),
  ('Almighty Flip',null,'7','2022-01-01','2020-01-01','Axel Weber','From Exposure do a front flip while hooking one foot under the line and putting it back on the line for the landing.','After 270 deg of rotation try to pull the line under yourself with your feet.','https://youtu.be/jIBjYEMRhrQ','EXPOSURE','EXPOSURE'),
  ('Barrel Almighty Flip',null,'7','2022-01-01','2020-01-01','Justin Wagers','Almighty flip but from normal stance.',null,'https://youtu.be/Se5XNo0RSP8?t=649','STAND','STAND'),
  ('Back Barrel Almighty Flip',null,'7','2022-01-01','2020-01-01','Justin Wagers','Like the Barrel Almighty Flip but flipping backside.',null,'https://youtu.be/Se5XNo0RSP8?t=426','STAND','STAND'),
  ('Back Almighty Flip',null,'7','2022-01-01','2020-01-01','Sebastian Egger','From Exposure do a back flip while hooking one foot under the line and putting it back on the line for the landing.','First lean back and then kick/hook the line.','https://youtu.be/jIBjYEMRhrQ','EXPOSURE','EXPOSURE'),
  ('Despedido','Back Korean Roll 360 to Chest','5','2022-01-01','2021-01-01','Sakalomo','Start with a Back Korean Roll during which you are leaning forward, move your legs above the line to transition into a 360, land in Korean.',null,'https://www.youtube.com/watch?v=7yLCyoHgUS0&t=1036','KOREAN','CHEST'),
  ('Kung Pao','Shrimp Double Flip','TBD','2022-01-01','2021-01-01','Ian Eisenberg','Do a Shrimpflip and in the same bounce another roll backwards around the line.',null,'https://www.instagram.com/p/CXPSK-BKQAg/','ROCKET','ROCKET'),
  ('Back No Soup',null,'7','2022-01-01','2021-01-01','Tim Odermatt','A Can of Soup without hands, basically a Back Almighty starting from Soup.','Throw your hands in the air at the bottom of the bounce, it will allow you to gain more momentum to finish the rotation.','https://www.instagram.com/p/CVvIbn3lFqU/','SOUP','EXPOSURE'),
  ('Whatever','Leash to Feet','7','2022-01-01','2021-01-01','Enzo Fuchs','Drop into the leash and on the way up climb the leash and finish with a Rocket Mount.',null,'https://www.instagram.com/p/CRyXVw0ISbI/','LEASH','EXPOSURE'),
  ('Sick Nasty from Feet to Feet',null,'6','2022-01-01','2021-01-01','Enzo Fuchs','Sick Nasty from Feet to Feet.',null,'https://www.instagram.com/p/CWQrmuTAwNl/','EXPOSURE','EXPOSURE'),
  ('Frog Flip','Back Roll from Chest to Feet','7','2022-01-01','2022-01-01','Ian Eisenberg','From Chest you push off the line with both hands to get into a Back Roll to Feet.',null,'https://www.instagram.com/p/CYPPtWFvkIg/','CHEST','STAND'),
  ('Fireball','Underflip to Feet','TBD','2022-05-09','2022-01-01','Cesare Bellamoli','From Korean, do a BS 270 spin and finish with a Back Belly Roll to Feet.',null,'https://youtu.be/eUguTccJblI?t=45','KOREAN','EXPOSURE'),
  ('Tre Flip','Tre Nasty Roll','7','2022-01-01','2021-01-01','Ian Eisenberg','Start with the motion of a Half Nasty 180 but pass your legs over the line once more and keep spinning to do a full 360 and then add a roll around the line to land back in the starting position.',null,'https://www.instagram.com/p/CUayzIYg49i/','SOFA','SOFA'),
  ('High''N''Mighty','No Foot Almighty Flip','7','2022-01-01','2021-01-01','Ian Eisenberg','Barrel Front Almighty Flip but instead of hooking the line with your foot you press the line against your leg.',null,'https://www.instagram.com/p/CVYpkmVg2FY/','STAND','STAND'),
  ('180 Backflop','180 Back Roll from Feet','6','2022-01-01','2021-01-01','Ian Eisenberg','Do a 180 and then do a Backflop.',null,'https://www.youtube.com/watch?v=A8O3iGYGPPk&t=135','STAND','KOREAN'),
  ('Panic Attack','NH Panic Roll to Feet','7','2022-01-01','2021-01-01','Ian Eisenberg','You do a Panic Roll to Feet but don''t use your hands to hold the line. Instead use your foot to hook the line and go to Feet.',null,'https://www.youtube.com/watch?v=7yLCyoHgUS0&t=1355','SOFA','EXPOSURE'),
  ('King Prawn','Shrimpflip 180 to Feet','7','2022-01-01','2021-01-01','Ian Eisenberg','Do a Shrimpflip 180 but then go to Feet.',null,'https://youtu.be/7yLCyoHgUS0?t=1560','ROCKET','EXPOSURE'),
  ('180 Frontflop','180 Front Roll from Feet','6','2022-01-01','2021-01-01','Ian Eisenberg','From Standing you turn 180 and do a Frontflop.',null,'https://youtu.be/A8O3iGYGPPk?t=116','STAND','KOREAN'),
  ('360 Orbital to Feet',null,'8','2022-01-01','2021-01-01','Ian Eisenberg','Orbital to Feet but with a 360 spin.',null,'https://youtu.be/A8O3iGYGPPk?t=175','STAND','STAND'),
  ('Darth Vader','Antihero to Feet','7','2022-01-01','2021-01-01','Ian Eisenberg','Like an Antihero but landing in Exposure.',null,'https://www.youtube.com/watch?v=V0fMaONFvVY','ROCKET','EXPOSURE'),
  ('Adrenaline Roll','90 to Yoda Roll','6','2022-01-01','2020-01-01','Ian Eisenberg','Do a 90 with restepping and go into a Yoda Roll.',null,'https://youtu.be/qLEnzTtvTcA?t=38','STAND','EXPOSURE'),
  ('Han Solo',null,'6','2022-01-01','2020-01-01','Jim Galli','Almighty Flip but instead of hooking the line with your foot you grab and pull on the leash.',null,'https://www.youtube.com/watch?v=dG9sJvKjg6E&t=323','EXPOSURE','EXPOSURE'),
  ('Backbounce Nirvana','Backbounce Panic Roll 180 to Feet','7','2022-01-01','2021-01-01','Justin Wagers','Nirvana from Backbounce.',null,'https://www.instagram.com/p/CSW1c4Li76j/','BACK','EXPOSURE'),
  ('Panic Double Roll to Feet',null,'7','2022-01-01','2021-01-01','Justin Wagers','Panic Roll with an additional roll landing to Feet.',null,'https://youtu.be/RDVaUFdqMmE?t=261','SOFA','EXPOSURE'),
  ('Double Can of Soup',null,'7','2022-01-01','2019-01-01','Justin Wagers','From Soup do a double roll and land on your feet in normal stance.',null,'https://youtu.be/rWqH_51ztQA?t=6977','SOUP','STAND'),
  ('Nirvana','Sofa Roll 360 to Feet','7','2022-01-01','2021-01-01','Salomé Cholet','Do a Sofa Roll 360 and land in Exposure.',null,'https://youtu.be/7yLCyoHgUS0?t=580','SOFA','EXPOSURE'),
  ('FS 360 Rocket Mount',null,'7','2022-01-01','2021-01-01','Sebastian Egger','Rocket Mount with a 360.','First spin a little bit into the opposite direction to then explode out the way you really want to spin.; Try to avoid doing a Rocket Mount 180 and then restep with your feet but go for the 360 right away.','https://www.instagram.com/p/CPgJRJHK777/','ROCKET','EXPOSURE'),
  ('Sofa 540 to Feet',null,'7','2022-01-01','2021-01-01','Sebastian Egger','Like a Sofa 360 to Feet but with a late 180.','Try to not do the 360 and then restep to get the 540 but instead go for the 540 directly.','https://www.instagram.com/p/CPgJRJHK777/','SOFA','EXPOSURE'),
  ('Flowflip from Feet to Feet','Switch 270 Yoda Roll Fake 90','7','2022-01-01','2021-01-01','Sebastian Egger','From switch do 270 spin and go into a Yoda Roll and finish by turning to normal stance.','Either start or land in switch.',null,'STAND','STAND'),
  ('Tesseract','Butter Roll to Feet','7','2022-01-01','2021-01-01','Ian Eisenberg','Start by doing the Butter and roll to your back, put your feet on the line to land in Expo.',null,'https://www.instagram.com/p/CVhgrM6B6jd/','SOFA','EXPOSURE'),
  ('180 Front Yoda Roll',null,'7','2022-01-01','2021-01-01','Ian Eisenberg','From Exposure do a 180 and during the spin go into the Yoda Roll.',null,'https://youtu.be/Ab2gW1rv5e8?t=22','EXPOSURE','EXPOSURE'),
  ('Dojo Roll','BS 270 Back Yoda Roll','7','2022-01-01','2021-01-01','Ian Eisenberg','Turn 180 to your BS and go into a Back Yoda Roll finishing the last 90 degrees of spin.',null,'https://youtu.be/BOGMXJsXWCE?t=31','STAND','EXPOSURE'),
  ('Dirty Sofa','Almighty from Sofa','7','2022-01-01','2021-01-01','Tim Odermatt','Start in Sofa, then bring one foot up to the line to hook it and go for an Almighty Flip.',null,null,'SOFA','EXPOSURE'),
  ('Double Shoulder Roll to Feet',null,'7','2022-01-01','2020-01-01','Enzo Fuchs','Double Shoulder Roll landing in Exposure.',null,'https://www.instagram.com/p/CFKdxdlq9yd/','SHOULDER','EXPOSURE'),
  ('Front Yoda Rewind',null,'8','2022-01-01','2021-01-01','Sebastian Egger','It''s almost a Front Yoda Roll and a Back Yoda Roll in the same bounce. Start at the very bottom of the bounce with a Front Yoda Roll so the line snaps up and after around three quarters of rotation you have some resistance of the line to push off of into the Back Yoda Roll.','Start a lot earlier than you would for most tricks.','https://youtu.be/aAq4Tf8naOM?t=135','EXPOSURE','EXPOSURE'),
  ('Back Yoda Rewind',null,'8','2022-01-01','2021-01-01','Tim Odermatt','It''s almost a Back Yoda Roll and a Front Yoda Roll in the same bounce. Start at the very bottom of the bounce with a Back Yoda Roll so the line snaps up and after around three quarters of rotation you have some resistance of the line to push off of into the Front Yoda Roll.','Start a lot earlier than you would for most tricks.',null,'EXPOSURE','EXPOSURE'),
  ('Tre Nasty to Feet',null,'TBD','2022-01-01','2021-01-01','Ian Eisenberg','Tre Nasty landing to Feet.',null,null,'SOFA','STAND'),
  ('Cosmonaut','360 Expo Orbital to Feet','8','2022-01-01','2021-01-01','Ian Eisenberg','Expoorbital to Feet with a 360 spin.',null,'https://youtu.be/lzz9jvtYpi0?t=567','EXPOSURE','EXPOSURE'),
  ('Lasagna Roll','Hammock Roll from Feet to Feet','8','2022-01-01','2021-01-01','Augustin Moinat','Hammock Roll starting from Feet and going directly back to Feet.',null,'https://youtu.be/aAq4Tf8naOM?t=139','STAND','STAND'),
  ('Total Nirvana','Panic Roll 180 from Feet to Feet','8','2022-01-01','2021-01-01','Sakalomo','Basically a Sofa Roll 360 from Feet to Feet.',null,'https://youtu.be/HecUpHXRpDw?t=55','EXPOSURE','EXPOSURE'),
  ('Backflip','Back Roll from Feet to Feet','8','2022-01-01','2021-01-01','Ian Eisenberg','It is a Back Roll from Feet to Feet.',null,'https://youtu.be/Ej2ocABoNC4?t=18588','STAND','STAND'),
  ('Supersonic Mount','Rocket Front Belly Roll to Feet','7','2022-01-01','2020-01-01','Ian Eisenberg','From Rocket get a lot of momentum with your feet and do one roll forward around the line and land in Exposure.',null,'https://www.youtube.com/watch?v=r5rwYkvnbco','ROCKET','EXPOSURE'),
  ('Back Turtle Roll','Double Back Yoda Roll','7','2022-01-01','2020-01-01','Ian Eisenberg','Two Back Yoda Rolls in one bounce.',null,'https://www.youtube.com/watch?v=RerW2T7edVA','EXPOSURE','EXPOSURE'),
  ('Darkside Roll','Sick Nasty Roll to Feet','7','2022-01-01','2020-01-01','Ian Eisenberg','Do a Sick Nasty Roll but instead of swinging both your legs over the line again put one foot on the line and keep the other one behind the line. Then put the second foot on and stick the trick.',null,'https://youtu.be/Ab2gW1rv5e8?t=79','SOFA','EXPOSURE'),
  ('180 Darth Vader',null,'8','2022-01-01','2021-01-01','Ian Eisenberg','Darth Vader with a 180.',null,'https://youtu.be/HecUpHXRpDw?t=218','ROCKET','EXPOSURE'),
  ('180 Almighty Flip',null,'8','2022-01-01','2021-01-01','Ian Eisenberg','Do a 180 and then go into a Front Almighty Flip.',null,'https://youtu.be/n2z3IyeQSj4?t=88','EXPOSURE','EXPOSURE'),
  ('Double Barrel Roll',null,'7','2022-01-01','2021-01-01','Justin Wagers','Double Barrel Roll.',null,'https://www.youtube.com/watch?v=VP49hErTqM0&t=415','STAND','STAND'),
  ('Frontflip (Chrysalis)','Frontroll from Feet to Feet','8','2022-01-01','2021-01-01','Nick Day','Front Roll from Feet to Feet.','Longer lines allow for more time to execute the trick.','https://www.youtube.com/watch?v=8fqUe9ZQvAc','STAND','STAND'),
  ('Turtle Roll','Double Yoda Roll','7','2022-01-01',null,'Pablo Signoret','Two Yoda Rolls in one bounce.',null,'https://www.youtube.com/watch?v=VP49hErTqM0&t=420','EXPOSURE','EXPOSURE'),
  ('Fake 360 Almighty Flip',null,'8','2022-01-01','2021-01-01','Sebastian Egger','Starting in switch do a 270 spin, go into a Front Almighty Flip and in the end turn 90 to look back at the same anchor as where you started.',null,'https://www.instagram.com/p/COPXx5vtOBy/','STAND','STAND'),
  ('Overflow','FS 360 Barrel Roll','TBD','2022-01-01','2021-01-01','Tim Odermatt','From your regular stance do a frontside 270 and roll around the line like you would for a Flowflip. Try to land back in your normal stance and not in Exposure.',null,'https://www.instagram.com/p/CSHcZfUFG9H/','STAND','STAND'),
  ('Barrel late Orbital 180',null,'TBD','2022-01-01','2021-01-01','Justin Wagers','Start with a Barrel Roll and then add an Orbital 180 in the same bounce.','You gotta be quick for this one.','https://www.instagram.com/p/CXJSAepFj4L/','STAND','CHEST'),
  ('Rubik''s Cube','Half Nasty 180 Front Sofa Roll to Feet','7','2022-01-01','2021-01-01','Ian Eisenberg','It''s a Half Nasty 180 with a Front Sofa Roll landing in Exposure.',null,'https://www.instagram.com/p/CPWrEFhKBUm/','SOFA','EXPOSURE'),
  ('Makako to Feet',null,'TBD','2022-01-01','2021-01-01','Sakalomo','Makako landing in Exposure.',null,'https://youtu.be/rWqH_51ztQA?t=5633','NEVERMIND','EXPOSURE'),
  ('Despedido to Feet',null,'TBD','2022-01-01','2021-01-01','Sakalomo','Despedido landing in Exposure',null,'https://youtu.be/HecUpHXRpDw?t=162','KOREAN','EXPOSURE'),
  ('180 Super Sonic Mount',null,'8','2022-01-01','2021-01-01','Ian Eisenberg','It''s a Super Sonic late 180 or Rocket Rewind to Feet.',null,'https://youtu.be/HecUpHXRpDw?t=249','ROCKET','EXPOSURE'),
  ('360 Almighty Flip',null,'8','2022-01-01','2021-01-01','Ian Eisenberg','360 Almighty Flip.',null,'https://youtu.be/HecUpHXRpDw?t=367','STAND','STAND'),
  ('Reverse Super Sonic Mount',null,'TBD','2022-01-01','2021-01-01','Samuel Volery','From Rocket get a lot of momentum with your feet and do one roll backwards around the line and land in Exposure.',null,'https://www.youtube.com/watch?v=EntnbHe_biY','ROCKET','EXPOSURE'),
  ('Ninja Shifta','Shapeshifter to Feet','8','2022-01-01','2021-01-01','Enzo Fuchs','Shapeshifter landing to feet.',null,'https://www.instagram.com/p/CXOfVZGgZ7b/','EXPOSURE','EXPOSURE'),
  ('Shrimpzilla','Kung Pao to Feet','TBD','2022-01-01','2021-01-01','Ian Eisenberg','Shrimpflip to Reverse Rocket Mount.',null,'https://www.instagram.com/p/CXXU9U7KvZ7/','ROCKET','EXPOSURE'),
  ('Megaminx','Half-Nasty 360 Roll to Feet','TBD','2022-01-01','2022-01-01','Ian Eisenberg','Start like you would for the Half-Nasty 180, but then keep spinning to do a 360 by regrabing your hands and finish Reverse Obi-Wan.',null,'https://www.instagram.com/p/C8ubJOaMydv/','SOFA','EXPOSURE'),
  ('180 Backflip',null,'TBD','2022-05-09','2022-01-01','Oscar Defoor','Start in regular position, rotate 180° backside and do a backflip starting from switch position. Roll over the same shoulder as the normal backflip.','Get the 180° backflop as solid as possible first!','https://www.instagram.com/p/CadBn6CjXqM/','STAND','EXPOSURE'),
  ('Double Dibahia','Double Back Roll from Feet','TBD','2022-05-09','2022-01-01','Ian Eisenberg','Double Backroll from feet.','Protecting your arm from leashburns could be beneficial.','https://www.instagram.com/p/CZh3qZata-5/','STAND','KOREAN'),
  ('Yodermatt','Double Back Yoda Roll 180','9','2022-05-09','2022-01-01','Tim Odermatt','Back Yoda Roll to Back Yoda Roll 180 in one bounce.',null,'https://www.instagram.com/p/Caf2ldqgtLc/','EXPOSURE','EXPOSURE'),
  ('Triple Back Yoda Roll',null,'9','2022-01-01','2021-01-01','Davis Hermes','Three Back Yoda Rolls in one bounce.',null,'https://www.instagram.com/p/CUNMWEgAGP4/','EXPOSURE','EXPOSURE'),
  ('Holy Grail','Barrel Almighty Flip to Barrel Roll','9','2022-01-01','2021-01-01','Davis Hermes','Start by doing a Barrel Almighty Flip and go for a second roll by grabbing the line and doing a Barrel Roll.',null,'https://youtu.be/UdG4DNI0SNk?t=92','STAND','STAND'),
  ('Eisenvader','Darth Vader from Feet','9','2022-01-01','2021-01-01','Ian Eisenberg','Start in Expo and roll down until you are in Rocket. Then do a Darth Vader.',null,'https://youtu.be/HecUpHXRpDw?t=436','EXPOSURE','EXPOSURE'),
  ('Double Back Almighty Flip',null,'9','2022-01-01','2021-01-01','Sebastian Egger','Double Back Almighty Flip.','Do the first one laid out and tuck for the second one to get good momentum.; Try to get the hook at your ankle. If the line is near your toes it''s hard to pull it around for the second roll.','https://youtu.be/HecUpHXRpDw?t=547','EXPOSURE','EXPOSURE'),
  ('Double Front Almighty Flip',null,'9','2022-01-01','2021-01-01','Sebastian Egger','Double Front Almighty Flip.','Stay open for the first one and tuck for the second one to get good momentum.','https://youtu.be/HecUpHXRpDw?t=780','EXPOSURE','EXPOSURE'),
  ('Double Boomerang','Front Sofa Roll Rewind to Sick Nasty Double Roll','TBD',now(),'2022-01-01','Ian Eisenberg','Start early with a Lightside Roll and use the resistance in the line to finish with a Double Sick Nasty Roll.',null,'https://youtu.be/rWqH_51ztQA?t=6940','SOFA','SOFA'),
  ('Shrimp Cocktail','Shrimpflip 360 to Feet','8',now(),'2022-01-01','Ian Eisenberg','Start with a Shrimpflip, let go with one hand to initiate the 360 spin and land in Exposure.',null,'https://www.instagram.com/p/CbV9q1_p8DI/','ROCKET','EXPOSURE'),
  ('Downward Spiral','360 from Feet to Korean','5',now(),'2022-01-01','Ian Eisenberg','Kick your back leg to the front, initiate a 360 with your upper body, and bring your front leg around to land in Korean.',null,'https://www.instagram.com/p/Cck9B16DcDi/','STAND','KOREAN'),
  ('Capoeira Flop','OH Back Handspring to Korean','TBD',now(),'2022-01-01','Ian Eisenberg','Do a OH Back Handspring to Korean.',null,'https://www.instagram.com/p/Cck9B16DcDi/','STAND','KOREAN'),
  ('Boomerang','Front Sofa Roll Rewind to Sick Nasty Roll','6',now(),'2022-01-01','Ian Eisenberg','Start early with a Lightside Roll and use the resistance in the line to finish with a Sick Nasty Roll.',null,'https://www.instagram.com/p/C87PZ0pMsjF/','SOFA','SOFA'),
  ('Sushi Backflop',null,'7',now(),'2022-05-01','Ian Eisenberg','Start with a early Sushi and go into the Backflop at the top of the bounce.',null,'https://www.instagram.com/p/CdsGGZrvNJ2/','STAND','KOREAN'),
  ('Shrimp Mount',null,'5',now(),'2022-05-01','Ian Eisenberg','From Rocket, stay below the line, pull just your legs up and kick in between the arms with extended legs. With the momentum from the leg kick, bring your body above the line, tuck your legs and land in Exposure.',null,'https://www.instagram.com/p/Cd7NRJeNEAa/','ROCKET','EXPOSURE'),
  ('Double Drop Knee Almighty',null,'TBD',now(),'2022-01-01','Ian Eisenberg','Almighty from DDK.',null,'https://www.instagram.com/p/CeVEh4DDYle/','DOUBLE DROPKNEE','EXPOSURE'),
  ('Bangarang','Boomerang to Feet','8',now(),'2022-01-01','Ian Eisenberg','Boomerang to Feet.',null,'https://www.instagram.com/p/DAyphTxipiv/','SOFA','EXPOSURE'),
  ('Back Panic Attack','No Hands Back Panic Roll to Feet','7',now(),'2022-01-01','Ian Eisenberg','From Sofa, bring your back leg over the line (like a heel hook), initiate a roll backwards and immediately hook with your front foot, finish the roll and put your feet back on the line to land the trick.',null,'https://www.instagram.com/p/Cfczh8IpvK4/','SOFA','EXPOSURE'),
  ('Boomerang 180','Front Sofa Roll Rewind to Mini-Cube','7',now(),'2022-01-01','Ian Eisenberg','This trick starts with an early Front Sofa Roll for which you grab both hands on your side (the Sick Nasty way). During the Front Sofa Roll, pass your legs over the line. Then use the resistance of the line to rewind your rolling direction and finish with the second half of a Mini-Cube.',null,'https://www.instagram.com/p/CgUkGA0uVlA/','SOFA','SOFA'),
  ('Reverse Rocket Mount 360',null,'TBD',now(),'2022-01-01','Ian Eisenberg','We haven''t figured out yet what''s going on here. Look at the video and help us by updating the description.',null,'https://www.instagram.com/p/CgUkGA0uVlA/','ROCKET','EXPOSURE'),
  ('Sushi-Flip','Sushi Backflip','9',now(),'2022-01-01','Ian Eisenberg','Start with an early Sushi and then do a Backflip at the top of the bounce.',null,'https://www.instagram.com/p/Cg8_eXWLmXw/','STAND','STAND'),
  ('NH Backflip',null,'9',now(),'2022-01-01','Ian Eisenberg','Do a Backflip without grabing the line.',null,'https://www.instagram.com/p/Cg_eTDJLsZ6/','STAND','STAND'),
  ('Batman',null,'5',now(),'2022-01-01','Ian Eisenberg','From Rocket, swing your legs to the side, hook the line with both feet, let go of your hands to "hang" on the line at the top of the bounce, finish the sidewards motion with your upper body and regrap with the hands. Let your feet go off the line to finish back in Rocket.',null,'https://www.instagram.com/p/ChsA7RvrV7m/','ROCKET','ROCKET'),
  ('Shark Bite',null,'4',now(),'2022-01-01','Ian Eisenberg','From Rocket, bite the line at the top of the bounce and let go of your hands at the same time. Regrab with your hands to finish the trick in Rocket at the bottom of the bounce.',null,'https://www.instagram.com/p/ChsA7RvrV7m/','ROCKET','ROCKET'),
  ('Double Darth Vader','Antihero to Sofa Roll to Feet','9',now(),'2022-01-01','Ian Eisenberg','Do an Antihero followed by a Sofa Roll to Feet in the same bounce.',null,'https://www.instagram.com/p/ChsjejWLu8d/','ROCKET','EXPOSURE'),
  ('All-Nasty','Darkside Almighty','8',now(),'2022-01-01','Ian Eisenberg','Start as you would for the Darkside Roll, but instead of putting the first foot on the line, hook it like for a Back Almighty, put the second foot on the line, let go of your hands and finish as you would for a Back Almighty.',null,'https://www.instagram.com/p/Chxgwo6s6g_/','SOFA','EXPOSURE'),
  ('540 Rocket to Sofa',null,'7',now(),'2022-01-01','Ian Eisenberg','From Rocket, pull yourself up half-way, then initiate the spin and land in Sofa.',null,'https://www.instagram.com/p/Ch11yrdsUEG/','ROCKET','SOFA'),
  ('360 Back Almighty',null,'8',now(),'2022-01-01','Ian Eisenberg','Do a FS 270 spin, followed by a Back Almighty and spin another 90 degrees to finish looking back at the anchor.',null,'https://www.instagram.com/p/Ch99aJdpyUo/','STAND','STAND'),
  ('Orbital to Double Drop Knee',null,'TBD',now(),'2022-01-01','Ian Eisenberg','Orbital to DDK.',null,'https://www.instagram.com/p/Cjkb1LXrFci/','STAND','DOUBLE DROPKNEE'),
  ('Shrimpy Hero','Shrimpflip 180 to Antihero','7',now(),'2022-01-01','Justin Wagers','Start with a Shrimpflip, let go with one hand to initiate the 180 and finish with an Antihero, landing in Sofa.',null,'https://www.instagram.com/p/CaPmmmsl1e3/','ROCKET','SOFA'),
  ('Back Attack','Backbounce Panic Attack','8',now(),'2022-01-01','Justin Wagers','NH Panic Roll to feet starting from Backbounce.',null,'https://www.instagram.com/p/Ce3cq4OIs0l/','BACK','EXPOSURE'),
