  ('360 Darth Vader',null,'9',now(),'2022-01-01','Justin Wagers','Do a 360 and a Darth Vader at the same time.',null,'https://www.instagram.com/p/Cgb_ScXIF86/','ROCKET','EXPOSURE'),
  ('Back Holy Grail',null,'9',now(),'2022-01-01','Justin Wagers','Do a Back Almighty and a Back Yoda Roll in one bounce.',null,'https://www.instagram.com/p/Cgt9fIHIsrr/','EXPOSURE','EXPOSURE'),
